// @vitest-environment jsdom
import { act, fireEvent, renderHook } from '@testing-library/react';
import { afterEach, describe, expect, it, vi } from 'vitest';
import { useClipDrag } from '@/tools/video-editor/hooks/useClipDrag';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackDefinition } from '@/tools/video-editor/types';

const baseTrack: TrackDefinition = {
  id: 'V1',
  kind: 'visual',
  label: 'V1',
  scale: 1,
  fit: 'manual',
  opacity: 1,
  blendMode: 'normal',
};

function makeCoordinator(): DragCoordinator {
  return {
    update: vi.fn(() => ({
      time: 0,
      rowIndex: 0,
      trackId: 'V1',
      trackKind: 'visual',
      trackName: 'V1',
      isNewTrack: false,
      isReject: false,
      newTrackKind: null,
      screenCoords: {
        rowTop: 0,
        rowLeft: 0,
        rowWidth: 0,
        rowHeight: 48,
        clipLeft: 0,
        clipWidth: 0,
        ghostCenter: 0,
      },
    })),
    showSecondaryGhosts: vi.fn(),
    end: vi.fn(),
    lastPosition: null,
    editAreaRef: { current: null },
  };
}

function makeData(): TimelineData {
  return {
    config: {
      output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' },
      tracks: [baseTrack],
      clips: [{ id: 'clip-1', at: 0, track: 'V1', clipType: 'hold', hold: 2 }],
    },
    configVersion: 1,
    registry: { assets: {} },
    resolvedConfig: {
      output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' },
      tracks: [baseTrack],
      clips: [{ id: 'clip-1', at: 0, track: 'V1', clipType: 'hold', hold: 2 }],
      registry: {},
    },
    rows: [{
      id: 'V1',
      actions: [{ id: 'clip-1', start: 0, end: 2, effectId: 'effect-clip-1' }],
    }],
    meta: {
      'clip-1': {
        track: 'V1',
        clipType: 'hold',
        hold: 2,
      },
    },
    effects: {
      'effect-clip-1': { id: 'effect-clip-1' },
    },
    assetMap: {},
    output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' },
    tracks: [baseTrack],
    clipOrder: { V1: ['clip-1'] },
    signature: 'sig-1',
    stableSignature: 'stable-1',
  };
}

function setupDom() {
  const wrapper = document.createElement('div');
  wrapper.className = 'timeline-wrapper';
  const editArea = document.createElement('div');
  editArea.className = 'timeline-canvas-edit-area';
  const clip = document.createElement('div');
  clip.className = 'clip-action';
  clip.dataset.clipId = 'clip-1';
  clip.dataset.rowId = 'V1';
  clip.getBoundingClientRect = () => ({
    x: 0,
    y: 0,
    left: 0,
    top: 0,
    right: 120,
    bottom: 24,
    width: 120,
    height: 24,
    toJSON: () => ({}),
  });
  editArea.appendChild(clip);
  wrapper.appendChild(editArea);
  document.body.appendChild(wrapper);

  return {
    clip,
    wrapper,
    cleanup: () => wrapper.remove(),
  };
}

afterEach(() => {
  document.body.innerHTML = '';
});

describe('useClipDrag', () => {
  it('increments on pointerdown and returns pendingOpsRef to 0 on pointerup', () => {
    const pendingOpsRef = { current: 0 };
    const { clip, wrapper, cleanup } = setupDom();
    const timelineWrapperRef = { current: wrapper };
    const dataRef = { current: makeData() };

    try {
      renderHook(() => useClipDrag({
        timelineWrapperRef,
        dataRef,
        pendingOpsRef,
        moveClipToRow: vi.fn(),
        createTrackAndMoveClip: vi.fn(),
        selectClip: vi.fn(),
        selectClips: vi.fn(),
        selectedClipIdsRef: { current: new Set<string>() },
        applyEdit: vi.fn(),
        coordinator: makeCoordinator(),
        rowHeight: 48,
        scale: 1,
        scaleWidth: 100,
        startLeft: 0,
      }));

      act(() => {
        fireEvent.pointerDown(clip, {
          button: 0,
          pointerId: 1,
          clientX: 24,
          clientY: 12,
        });
      });
      expect(pendingOpsRef.current).toBe(1);

      act(() => {
        fireEvent.pointerUp(window, {
          pointerId: 1,
          clientX: 24,
          clientY: 12,
        });
      });
      expect(pendingOpsRef.current).toBe(0);
    } finally {
      cleanup();
    }
  });

  it('returns pendingOpsRef to 0 on pointercancel', () => {
    const pendingOpsRef = { current: 0 };
    const { clip, wrapper, cleanup } = setupDom();
    const timelineWrapperRef = { current: wrapper };
    const dataRef = { current: makeData() };

    try {
      renderHook(() => useClipDrag({
        timelineWrapperRef,
        dataRef,
        pendingOpsRef,
        moveClipToRow: vi.fn(),
        createTrackAndMoveClip: vi.fn(),
        selectClip: vi.fn(),
        selectClips: vi.fn(),
        selectedClipIdsRef: { current: new Set<string>() },
        applyEdit: vi.fn(),
        coordinator: makeCoordinator(),
        rowHeight: 48,
        scale: 1,
        scaleWidth: 100,
        startLeft: 0,
      }));

      act(() => {
        fireEvent.pointerDown(clip, {
          button: 0,
          pointerId: 2,
          clientX: 24,
          clientY: 12,
        });
      });
      expect(pendingOpsRef.current).toBe(1);

      act(() => {
        fireEvent.pointerCancel(window, {
          pointerId: 2,
          clientX: 24,
          clientY: 12,
        });
      });
      expect(pendingOpsRef.current).toBe(0);
    } finally {
      cleanup();
    }
  });
});

import { describe, expect, it } from 'vitest';
import { applyMultiDragMoves } from '@/tools/video-editor/lib/multi-drag-utils';
import { resolveGroupOverlaps, resolveOverlaps } from '@/tools/video-editor/lib/resolve-overlaps';
import type { ClipMeta, TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackDefinition } from '@/tools/video-editor/types';
import type { TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

const makeTrack = (id: string): TrackDefinition => ({
  id,
  kind: 'visual',
  label: id,
  scale: 1,
  fit: 'manual',
  opacity: 1,
  blendMode: 'normal',
});

const makeAction = (id: string, start: number, end: number) => ({
  id,
  start,
  end,
  effectId: `effect-${id}`,
});

describe('resolve-overlaps utilities', () => {
  it('returns overlap adjustments and timed meta patches for single-clip overlap resolution', () => {
    const rows: TimelineRow[] = [{
      id: 'V1',
      actions: [
        makeAction('sibling', 0, 2),
        makeAction('clip-1', 1, 4),
      ],
    }];
    const meta: Record<string, ClipMeta> = {
      'clip-1': { track: 'V1', clipType: 'media', from: 0, to: 3, speed: 1 },
    };

    const result = resolveOverlaps(rows, 'V1', 'clip-1', meta);

    expect(result.rows[0]?.actions.find((action) => action.id === 'clip-1')).toMatchObject({
      start: 2,
      end: 5,
    });
    expect(result.metaPatches['clip-1']).toEqual({ from: 1, to: 4 });
    expect(result.adjustments).toEqual([
      { clipId: 'clip-1', requestedStart: 1, actualStart: 2 },
    ]);
  });

  it('returns timed meta patches when a moved clip group is gap-fit to a later start', () => {
    const rows: TimelineRow[] = [{
      id: 'V1',
      actions: [
        makeAction('sibling', 0, 2),
        makeAction('clip-a', 4, 6),
        makeAction('clip-b', 6, 8),
      ],
    }];
    const meta: Record<string, ClipMeta> = {
      'clip-a': { track: 'V1', clipType: 'media', from: 0, to: 2, speed: 1 },
      'clip-b': { track: 'V1', clipType: 'media', from: 0, to: 2, speed: 1 },
    };

    const result = resolveGroupOverlaps(rows, [
      { rowId: 'V1', clipId: 'clip-a', newStart: 1, newEnd: 3 },
      { rowId: 'V1', clipId: 'clip-b', newStart: 3, newEnd: 5 },
    ], meta);

    expect(result.rows[0]?.actions.find((action) => action.id === 'clip-a')).toMatchObject({
      start: 2,
      end: 4,
    });
    expect(result.rows[0]?.actions.find((action) => action.id === 'clip-b')).toMatchObject({
      start: 4,
      end: 6,
    });
    expect(result.metaPatches).toEqual({
      'clip-a': { from: 1, to: 3 },
      'clip-b': { from: 1, to: 3 },
    });
  });

  it('accumulates cross-track and overlap meta patches across multiple target rows', () => {
    const tracks = ['V1', 'V2', 'V3', 'V4'].map(makeTrack);
    const rows: TimelineRow[] = [
      { id: 'V1', actions: [makeAction('clip-a', 0, 2)] },
      { id: 'V2', actions: [makeAction('blocker-a', 0, 1)] },
      { id: 'V3', actions: [makeAction('clip-b', 0, 2)] },
      { id: 'V4', actions: [makeAction('blocker-b', 0, 1)] },
    ];
    const meta: Record<string, ClipMeta> = {
      'clip-a': { track: 'V1', clipType: 'media', from: 0, to: 2, speed: 1 },
      'clip-b': { track: 'V3', clipType: 'media', from: 0, to: 2, speed: 1 },
      'blocker-a': { track: 'V2', clipType: 'hold', hold: 1 },
      'blocker-b': { track: 'V4', clipType: 'hold', hold: 1 },
    };
    const data: TimelineData = {
      config: { output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' }, tracks, clips: [] },
      configVersion: 1,
      registry: { assets: {} },
      resolvedConfig: {
        output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' },
        tracks,
        clips: [],
        registry: {},
      },
      rows,
      meta,
      effects: {},
      assetMap: {},
      output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' },
      tracks,
      clipOrder: {
        V1: ['clip-a'],
        V2: ['blocker-a'],
        V3: ['clip-b'],
        V4: ['blocker-b'],
      },
      signature: 'sig-1',
      stableSignature: 'stable-1',
    };

    const result = applyMultiDragMoves(data, [
      { clipId: 'clip-a', sourceRowId: 'V1', targetRowId: 'V2', newStart: 0 },
      { clipId: 'clip-b', sourceRowId: 'V3', targetRowId: 'V4', newStart: 0 },
    ]);

    expect(result.metaUpdates).toEqual({
      'clip-a': { track: 'V2', from: 1, to: 3 },
      'clip-b': { track: 'V4', from: 1, to: 3 },
    });
    expect(result.nextRows.find((row) => row.id === 'V2')?.actions.find((action) => action.id === 'clip-a')).toMatchObject({
      start: 1,
      end: 3,
    });
    expect(result.nextRows.find((row) => row.id === 'V4')?.actions.find((action) => action.id === 'clip-b')).toMatchObject({
      start: 1,
      end: 3,
    });
  });
});

