import {
  forwardRef,
  useImperativeHandle,
  useLayoutEffect,
  useState,
  type MutableRefObject,
} from 'react';
import { createPortal } from 'react-dom';
import type { GhostRect } from '@/tools/video-editor/lib/multi-drag-utils';

export interface DropIndicatorPosition {
  rowTop: number;
  rowHeight: number;
  rowLeft: number;
  rowWidth: number;
  lineLeft: number;
  ghostLeft: number;
  ghostTop: number;
  ghostWidth: number;
  ghostHeight: number;
  ghostLabel: string;
  label: string;
  isNewTrack: boolean;
  isNewTrackTop?: boolean;
  trackId?: string;
  /** When non-null, describes the kind of track that will be created. */
  newTrackKind: string | null;
  reject: boolean;
}

export interface DropIndicatorHandle {
  show(position: DropIndicatorPosition): void;
  showSecondaryGhosts(ghosts: GhostRect[]): void;
  hide(): void;
}

interface DropIndicatorProps {
  editAreaRef: MutableRefObject<HTMLElement | null>;
  onNewTrackLabel?: (label: string | null) => void;
}

export const DropIndicator = forwardRef<DropIndicatorHandle, DropIndicatorProps>(function DropIndicator(
  { editAreaRef, onNewTrackLabel },
  ref,
) {
  const [position, setPosition] = useState<DropIndicatorPosition | null>(null);
  const [secondaryGhosts, setSecondaryGhosts] = useState<GhostRect[]>([]);

  useImperativeHandle(ref, () => ({
    show(nextPosition) {
      setPosition(nextPosition);
    },
    showSecondaryGhosts(ghosts) {
      setSecondaryGhosts(ghosts);
    },
    hide() {
      setPosition(null);
      setSecondaryGhosts([]);
    },
  }), []);

  useLayoutEffect(() => {
    const editArea = editAreaRef.current;
    if (!editArea) {
      return undefined;
    }

    // Only show the "create new track" affordance when dragging below all rows
    // (not for kind-mismatch redirects — those resolve silently to a compatible track)
    const showNewTrack = position?.isNewTrack === true && position?.trackId === undefined;
    editArea.classList.toggle('drop-target-new-track', showNewTrack);

    if (showNewTrack) {
      const kind = position?.newTrackKind ?? 'visual';
      const where = position?.isNewTrackTop ? 'top' : 'bottom';
      onNewTrackLabel?.(`Drop to create new ${kind} track at ${where}`);
    } else {
      onNewTrackLabel?.(null);
    }

    return () => {
      editArea.classList.remove('drop-target-new-track');
      onNewTrackLabel?.(null);
    };
  }, [editAreaRef, onNewTrackLabel, position?.isNewTrack, position?.isNewTrackTop, position?.newTrackKind, position?.trackId]);

  if (!position || typeof document === 'undefined') {
    return null;
  }

  const labelLeft = position.lineLeft - 30;
  const labelTop = position.rowTop - 16;

  return createPortal(
    <>
      <div
        className={position.reject ? 'drop-indicator-row drop-indicator-row--reject' : 'drop-indicator-row'}
        style={{
          left: position.rowLeft,
          top: position.rowTop,
          width: position.rowWidth,
          height: position.rowHeight,
          zIndex: 99998,
        }}
      />
      {!position.isNewTrack && (
        <>
          <div
            className="drop-indicator-line"
            style={{ left: position.lineLeft, top: position.rowTop, height: position.rowHeight, zIndex: 99999 }}
          />
          <div
            className="drop-indicator-ghost"
            style={{
              left: position.ghostLeft,
              top: position.ghostTop,
              width: position.ghostWidth,
              height: position.ghostHeight,
              zIndex: 99998,
            }}
          >
            <span className="drop-indicator-ghost-label">{position.ghostLabel}</span>
          </div>
          <div
            className="drop-indicator-label"
            style={{ left: labelLeft, top: labelTop, zIndex: 100000 }}
          >
            {position.label}
          </div>
        </>
      )}
      {secondaryGhosts.map((ghost, i) => (
        <div
          key={i}
          className="drop-indicator-ghost"
          style={{
            left: ghost.left,
            top: ghost.top,
            width: ghost.width,
            height: ghost.height,
            zIndex: 99997,
            opacity: 0.6,
          }}
        />
      ))}
    </>,
    document.body,
  );
});

export const computeDropPosition = ({
  clientX,
  clientY,
  wrapper,
  dataRef,
  scale,
  scaleWidth,
  startLeft,
  rowHeight,
  sourceKind = null,
  clipDuration = 5,
  clipOffsetX,
}: ComputeDropPositionParams): DropPosition => {
  const current = dataRef.current;
  const { editArea, grid } = getTimelineDomNodes(wrapper);
  const wrapperRect = wrapper.getBoundingClientRect();
  const editRect = (editArea ?? wrapper).getBoundingClientRect();
  const scrollLeft = grid?.scrollLeft ?? 0;
  const scrollTop = grid?.scrollTop ?? 0;
  const pixelsPerSecond = scaleWidth / scale;
  const effectiveOffsetX = clipOffsetX ?? (clipDuration * pixelsPerSecond) / 2;
  const leftInGrid = clientX - editRect.left + scrollLeft - effectiveOffsetX;
  const time = Math.max(0, (leftInGrid - startLeft) / pixelsPerSecond);

  const rowCount = current?.rows.length ?? 0;
  const rawRowIndex = rawRowIndexFromY(clientY, editRect.top, scrollTop, rowHeight);
  const isNewTrackBottom = rowCount === 0 || rawRowIndex >= rowCount;
  // Only show top drop zone when fully scrolled up — otherwise auto-scroll handles it
  const isNewTrackTop = rawRowIndex < 0 && rowCount > 0 && scrollTop < 2;
  const isNewTrack = isNewTrackBottom || isNewTrackTop;
  const rowIndex = rowCount === 0
    ? 0
    : isNewTrackBottom
      ? rowCount
      : isNewTrackTop
        ? 0
        : Math.min(Math.max(rawRowIndex, 0), rowCount - 1);
  const visualRowIndex = rowCount > 0 ? Math.min(rowIndex, rowCount - 1) : -1;
  const targetRow = visualRowIndex >= 0 ? current?.rows[visualRowIndex] : undefined;
  const targetTrack = visualRowIndex >= 0 ? current?.tracks[visualRowIndex] : undefined;
  const rowTop = visualRowIndex >= 0
    ? editRect.top + visualRowIndex * rowHeight - scrollTop
    : editRect.top;
  const clipLeft = editRect.left + startLeft + time * pixelsPerSecond - scrollLeft;
  const clipWidth = Math.max(0, Math.min(clipDuration * pixelsPerSecond, editRect.right - clipLeft));
  const ghostCenter = clipLeft + clipWidth / 2;
  const kindMismatch = !isNewTrack && sourceKind !== null && targetTrack?.kind !== undefined && sourceKind !== targetTrack.kind;

  // When kind doesn't match, silently resolve to the first compatible track.
  // Only create a new track if no compatible one exists at all.
  let resolvedTrackId = targetRow?.id;
  let resolvedTrackName = targetTrack?.label ?? targetTrack?.id ?? '';
  let resolvedTrackKind = targetTrack?.kind ?? null;
  let needsNewTrack = isNewTrack;
  let newTrackKind: TrackKind | null = isNewTrack ? sourceKind : null;

  if (kindMismatch && current && sourceKind) {
    // Find the nearest compatible track to the hovered row
    const compatibleTracks = current.tracks
      .map((t, i) => ({ track: t, index: i }))
      .filter(({ track }) => track.kind === sourceKind);
    const nearest = compatibleTracks.length > 0
      ? compatibleTracks.reduce((best, candidate) =>
          Math.abs(candidate.index - rowIndex) < Math.abs(best.index - rowIndex) ? candidate : best)
      : null;
    if (nearest) {
      const compatible = nearest.track;
      resolvedTrackId = compatible.id;
      resolvedTrackName = compatible.label ?? compatible.id;
      resolvedTrackKind = compatible.kind;
      const compatibleIndex = nearest.index;
      const compatibleRowTop = compatibleIndex >= 0
        ? editRect.top + compatibleIndex * rowHeight - scrollTop
        : rowTop;
      return {
        time,
        rowIndex: compatibleIndex,
        trackId: resolvedTrackId,
        trackKind: resolvedTrackKind,
        trackName: resolvedTrackName,
        isNewTrack: false,
        isReject: false,
        newTrackKind: null,
        screenCoords: {
          rowTop: compatibleRowTop,
          rowLeft: wrapperRect.left,
          rowWidth: wrapperRect.width,
          rowHeight,
          clipLeft,
          clipWidth,
          ghostCenter,
        },
      };
    }
    // No compatible track exists — will create one silently on drop
    needsNewTrack = true;
    newTrackKind = sourceKind;
    resolvedTrackId = undefined;
    resolvedTrackKind = sourceKind;
    resolvedTrackName = '';
  }

  return {
    time,
    rowIndex,
    trackId: needsNewTrack ? undefined : resolvedTrackId,
    trackKind: needsNewTrack ? sourceKind : resolvedTrackKind,
    trackName: resolvedTrackName,
    isNewTrack: needsNewTrack,
    isNewTrackTop: needsNewTrack && isNewTrackTop,
    isReject: false,
    newTrackKind,
    screenCoords: {
      rowTop,
      rowLeft: wrapperRect.left,
      rowWidth: wrapperRect.width,

    rowWidth: 0,
    rowHeight,
    clipLeft: 0,
    clipWidth: 0,
    ghostCenter: 0,
  },
});

